"use client";

import React, { useState } from 'react';
import axios from 'axios';

export default function GuardianSettings() {
    const [friends, setFriends] = useState([]);
    const [loading, setLoading] = useState(false);

    // 🚀 에러 1 해결: token을 함수 내부에서 가져오도록 정의
    const getAuthToken = () => localStorage.getItem('token');

    // 친구 목록 불러오기
    const fetchFriends = async () => {
        const token = getAuthToken();
        if (!token) return alert("로그인이 필요합니다.");

        setLoading(true);
        try {
            const res = await axios.get('http://localhost:8080/api/medication/kakao/friends', {
                headers: { Authorization: `Bearer ${token}` }
            });
            // 카카오 응답 구조에 따라 elements 추출
            setFriends(res.data.elements || []);
        } catch (e) {
            console.error("친구 목록 로드 실패", e);
            alert("친구 목록을 불러올 수 없습니다. 권한 설정을 확인해주세요.");
        } finally {
            setLoading(false);
        }
    };

    // 🚀 에러 3 해결: saveGuardian 함수 정의
    const saveGuardian = async (uuid: string, nickName: string) => {
        const token = getAuthToken();
        if (!confirm(`[${nickName}] 님을 보호자로 지정하시겠습니까?`)) return;

        try {
            await axios.post('http://localhost:8080/api/member/guardian', {
                guardianUuid: uuid,
                guardianName: nickName
            }, {
                headers: { Authorization: `Bearer ${token}` }
            });
            alert("✅ 보호자 지정이 완료되었습니다!");
            setFriends([]); // 목록 닫기
        } catch (e) {
            alert("보호자 저장 중 오류가 발생했습니다.");
        }
    };

    // 🚀 에러 2 해결: 모든 코드는 반드시 이 return (함수 바디) 안에 있어야 합니다.
    return (
        <div style={{ marginTop: '30px', padding: '20px', backgroundColor: '#f9fafb', borderRadius: '15px', border: '1px solid #e5e7eb' }}>
            <h3 style={{ marginBottom: '10px', fontSize: '18px', fontWeight: 'bold' }}>👩‍👧‍👦 보호자 연결 (카카오톡)</h3>
            <p style={{ fontSize: '13px', color: '#64748b', marginBottom: '15px' }}>
                20분간 복약 확인이 안 될 경우, 선택한 보호자에게 알림이 전송됩니다.
            </p>
            
            <button 
                onClick={fetchFriends} 
                disabled={loading}
                style={{ 
                    padding: '12px 20px', backgroundColor: '#fee500', border: 'none', 
                    borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', width: '100%' 
                }}
            >
                {loading ? "불러오는 중..." : "내 카톡 친구 목록 불러오기"}
            </button>
            
            <div style={{ marginTop: '15px', display: 'flex', flexDirection: 'column', gap: '10px' }}>
                {friends.map((f: any) => (
                    <div key={f.uuid} style={{ 
                        display: 'flex', justifyContent: 'space-between', alignItems: 'center', 
                        padding: '12px', backgroundColor: '#fff', borderRadius: '10px', border: '1px solid #e5e7eb' 
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                            {f.profile_thumbnail_image && (
                                <img src={f.profile_thumbnail_image} alt="profile" style={{ width: '30px', height: '30px', borderRadius: '50%' }} />
                            )}
                            <span style={{ fontWeight: '600' }}>{f.profile_nickname}</span>
                        </div>
                        <button 
                            onClick={() => saveGuardian(f.uuid, f.profile_nickname)}
                            style={{ 
                                padding: '6px 12px', backgroundColor: '#4f46e5', color: '#fff', 
                                border: 'none', borderRadius: '6px', cursor: 'pointer', fontSize: '12px', fontWeight: 'bold'
                            }}
                        >
                            지정
                        </button>
                    </div>
                ))}
            </div>
        </div>
    );
}